// app/api/upload/route.ts - CLIENT FIREBASE ONLY (Vercel-safe)
import { NextResponse } from 'next/server';
import { getStorage, ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import { initializeApp } from 'firebase/app';

const firebaseConfig = {
  apiKey: process.env.NEXT_PUBLIC_FIREBASE_API_KEY!,      // ✅ Your .env.local
  authDomain: process.env.NEXT_PUBLIC_FIREBASE_AUTH_DOMAIN!,
  projectId: process.env.NEXT_PUBLIC_FIREBASE_PROJECT_ID!,
  storageBucket: process.env.NEXT_PUBLIC_FIREBASE_STORAGE_BUCKET!,  // ✅ car-manual-ai-5c053.firebasestorage.app
  messagingSenderId: process.env.NEXT_PUBLIC_FIREBASE_MESSAGING_SENDER_ID!,
  appId: process.env.NEXT_PUBLIC_FIREBASE_APP_ID!
};

// Initialize ONLY client Firebase
const app = initializeApp(firebaseConfig);
const storage = getStorage(app);

export async function POST(request: Request) {
  try {
    const formData = await request.formData();
    const file = formData.get('file') as File;
    
    if (!file) {
      return NextResponse.json({ error: 'No file' }, { status: 400 });
    }

    const manualId = file.name.replace(/[^a-z0-9.]/gi, '_');
const storageRef = ref(storage, `manuals/${manualId}`);

// REAL FIREBASE UPLOAD
const snapshot = await uploadBytes(storageRef, file);
const url = await getDownloadURL(storageRef);


    return NextResponse.json({
      success: true,
      manualId,
      url,
      message: `✅ ${file.name} (${Math.round(file.size/1000000)}MB) added to garage!`
    });

  } catch (error) {
    console.error('Upload error:', error);
    return NextResponse.json({ error: 'Upload failed' }, { status: 500 });
  }
}










